import companyData from './mock/compData.json'
import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'


export function getClientList(isNotify) {
  let isTest = false
  if (isTest) {
  return new Promise(function(resolve, reject) {
    let res = { list: [] }
      companyData.list.forEach(item => {
          res.list.push(item)
      })
      resolve(res)
    })
  }
  return request({
    url: `/api/getClientList`,
    meta: { apiVersion: '1.0.0' },
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    Notify: { use: isNotify, apitype: 'searched' } //searched, saved,deleted
  })
}
  
export function getClientData(param,isNotify) {
  let isTest = false
  let data =param
  if (isTest) {
  return new Promise(function(resolve, reject) {
    let res = { list: [] }
      companyData.list.forEach(item => {
        if(item.clntId === param || param == null)
          res.list.push(item)
      })
      resolve(res)
    })
  }
  return request({
    url: `/api/getClientData`,
    meta: { apiVersion: '1.0.0' },
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    data:param,
    Notify: { use: isNotify, apitype: 'searched' } //searched, saved,deleted
  })
}

