<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <v-layout row>
        <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
          <i-card-top
            class="d-flex"
            headerTitle=""
            :useBtnList="buttonUseList"
            @btnSearch="btnSearch(true)"
            @btnAdd="btnAdd()"
            @btnSave="btnSave()"
            @btnDelete="btnDelete()"
          >
            <template v-slot:body>
              <v-layout overflow-auto> </v-layout>
            </template>
          </i-card-top>
        </v-col>
        <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
          <i-card-vertical headerTitle="사업장 관리" device="web">
            <template v-slot:body>
              <v-layout column>
                <v-col cols="12" md="12" class="row pa-0">
                  <v-col cols="12" class="pa-0">
                    <DxDataGrid
                      id="companyDataGrid"
                      class="layout-col-height00"
                      :ref="dxDataGridRef"
                      :data-source="companys"
                      :remote-operations="false"
                      :hover-state-enabled="true"
                      :allow-column-reordering="true"
                      :allow-column-resizing="true"
                      :row-alternation-enabled="true"
                      :column-auto-width="true"
                      :show-borders="true"
                      :show-row-lines="true"
                      :selection="{ mode: 'single' }"
                      key-expr="id"
                      :focused-row-enabled="true"
                      @row-updating="onRowUpdating"
                      @editing-start="onEditingStart"
                      @editor-preparing="onEditorPreparing"
                      @content-ready="onContentReady"
                    >
                      <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                      <DxSelection :select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                      <DxColumn
                        data-field="clntId"
                        data-type="string"
                        width="80px"
                        alignment="left"
                        caption="고객 번호"
                        css-class="devest-grid-header-require"
                        :hiding-priority="17"
                      >
                        <DxLookup :data-source="clientList" value-expr="clntId" display-expr="clntId" />
                      </DxColumn>

                      <DxColumn data-field="clntNm" data-type="string" width="100px" alignment="left" caption="고객 이름" :hiding-priority="21" />

                      <DxColumn
                        data-field="compId"
                        data-type="string"
                        width="100px"
                        alignment="left"
                        caption="사업장 번호"
                        css-class="devest-grid-header-require"
                        :hiding-priority="19"
                        header-cell-template="compIdHeader"
                      />
                      <template #compIdHeader>
                        <span>
                          사업장 번호
                          <v-tooltip top>
                            <template v-slot:activator="{ on, attrs }">
                              <v-icon small v-bind="attrs" v-on="on" class="mx-1">
                                mdi-help-circle
                              </v-icon>
                            </template>
                            <span>
                              사업장 번호는 영문 및 숫자 1~10자리로 입력이 가능합니다.
                            </span>
                          </v-tooltip>
                        </span>
                      </template>

                      <DxColumn
                        data-field="compNm"
                        data-type="string"
                        width="120px"
                        alignment="left"
                        caption="사업장명"
                        css-class="devest-grid-header-require"
                        :hiding-priority="20"
                      />

                      <DxColumn
                        data-field="rpstNm"
                        data-type="string"
                        width="100px"
                        alignment="left"
                        caption="대표자"
                        css-class="devest-grid-header-require"
                        :hiding-priority="18"
                      />

                      <DxColumn
                        data-field="rgstNo"
                        data-type="string"
                        width="110px"
                        alignment="left"
                        caption="사업자등록번호"
                        css-class="devest-grid-header-require"
                        :hiding-priority="16"
                      >
                      </DxColumn>

                      <DxColumn data-field="corpNo" data-type="string" width="120px" alignment="left" caption="법인등록번호" :hiding-priority="15">
                      </DxColumn>

                      <DxColumn data-field="bizCd" data-type="string" alignment="left" caption="업종코드" :hiding-priority="14" />

                      <DxColumn data-field="bizNm" data-type="string" width="150px" alignment="left" caption="업종명" :hiding-priority="13" />

                      <DxColumn
                        data-field="zipCd"
                        data-type="string"
                        width="120px"
                        alignment="center"
                        caption="우편번호"
                        cell-template="PostBoxTemplate"
                        edit-cell-template="PostBoxEditor"
                        :hiding-priority="12"
                      />

                      <DxColumn data-field="addrs1" data-type="string" width="200px" alignment="left" caption="주소" :hiding-priority="11" />

                      <DxColumn data-field="addrs2" data-type="string" width="150px" alignment="left" caption="상세주소" :hiding-priority="10" />

                      <DxColumn data-field="addrsEn1" data-type="string" width="200px" alignment="left" caption="주소(영문)" :hiding-priority="9" />

                      <DxColumn
                        data-field="addrsEn2"
                        data-type="string"
                        width="150px"
                        alignment="left"
                        caption="상세주소(영문)"
                        :hiding-priority="8"
                      />

                      <DxColumn data-field="telNo" data-type="string" alignment="left" caption="전화번호" :hiding-priority="7"> </DxColumn>

                      <DxColumn data-field="faxNo" data-type="string" alignment="left" caption="팩스번호" :hiding-priority="6"> </DxColumn>

                      <DxColumn data-field="email" data-type="string" alignment="left" caption="이메일" :hiding-priority="5" />

                      <DxColumn data-field="natnCd" data-type="string" alignment="center" caption="국가코드" :visible="false" />

                      <DxColumn data-field="bankCd" data-type="string" alignment="center" caption="은행코드" :hiding-priority="4" />

                      <DxColumn data-field="bankNo" data-type="string" alignment="left" caption="계좌번호" :hiding-priority="3" />

                      <DxColumn data-field="sealFileNm" caption="파일명" data-type="string" alignment="left" :visible="false" />

                      <DxColumn data-field="sealFile" caption="파일" data-type="string" alignment="left" :visible="false" />

                      <DxColumn data-field="sealFileId" caption="파일아이디" data-type="number" alignment="left" :visible="false" />

                      <DxColumn data-field="seal__fileUpdate__" caption="파일수정여부" data-type="boolean" alignment="left" :visible="false" />

                      <DxColumn
                        data-field="seal"
                        :width="400"
                        cell-template="extensionIconTemplate"
                        edit-cell-template="extensionIconTemplate"
                        caption="직인"
                        alignment="left"
                        :hiding-priority="2"
                      />

                      <DxColumn data-field="logoFileNm" caption="파일명" data-type="string" alignment="left" :visible="false" />

                      <DxColumn data-field="logoFile" caption="파일" data-type="string" alignment="left" :visible="false" />

                      <DxColumn data-field="logoFileId" caption="파일아이디" data-type="number" alignment="left" :visible="false" />

                      <DxColumn data-field="logo__fileUpdate__" caption="파일수정여부" data-type="boolean" alignment="left" :visible="false" />

                      <DxColumn
                        data-field="logo"
                        :width="400"
                        cell-template="extensionIconTemplate"
                        edit-cell-template="extensionIconTemplate"
                        caption="로고"
                        alignment="left"
                        :hiding-priority="1"
                      />

                      <DxColumn data-field="desc" data-type="string" alignment="center" caption="설명" :hiding-priority="0" />

                      <template #PostBoxTemplate="{data: cellInfo}">
                        <div
                          v-if="cellInfo.value != '' && cellInfo.value != null"
                          no-gutters
                          class="dx-adaptive-item-text d-flex justify-center align-center"
                        >
                          <div class="pl-1 pr-0">{{ cellInfo.value }}</div>
                          <!-- <v-spacer /> -->
                          <div class="text-right pr-2">
                            <v-btn text icon x-small @click="resetZipCd(cellInfo)">
                              <v-icon>
                                mdi-close
                              </v-icon>
                            </v-btn>
                          </div>
                        </div>
                        <v-row v-else no-gutters class="dx-adaptive-item-text">
                          <v-col cols="11" class="pl-1 pr-0">{{ cellInfo.value }}</v-col>
                          <!-- <v-spacer /> -->
                          <v-col class="text-right pr-2" cols="1"> </v-col>
                        </v-row>
                      </template>

                      <template #PostBoxEditor="{ data: cellInfo }">
                        <div>
                          <!-- <DxCheckBox :value="cellInfo.value == 'Y' ? true : false" :onValueChanged="value => onCheckValueChanged(value, cellInfo)" /> -->
                          <DxDropDownBox
                            @value-changed="onPostValueChanged(value, cellInfo)"
                            v-model="cellInfo.value"
                            :displayExpr="setPostCd"
                            :ref="postCdDropBoxRefName"
                            :drop-down-options="dropDownOptions"
                            @opened="onOpened"
                            @closed="onClosed"
                            content-template="contentTemplate"
                          >
                            <template #contentTemplate="{}">
                              <vue-daum-postcode
                                v-if="postVisible"
                                style="height: 500px; overflow: scroll;"
                                q=""
                                :animation="false"
                                :no-shorthand="true"
                                :no-auto-mapping="true"
                                :please-read-guide="1"
                                :please-read-guide-timer="1"
                                :max-suggest-items="3"
                                :show-more-h-name="false"
                                :hide-map-btn="true"
                                :hide-eng-btn="true"
                                :always-show-eng-addr="true"
                                :zonecode-only="true"
                                :theme="{
                                  outlineColor: '#44444'
                                }"
                                @onsearch="getSearch($event)"
                                @complete="getAddress($event, cellInfo)"
                              />
                            </template>
                          </DxDropDownBox>
                        </div>
                      </template>

                      <template #extensionIconTemplate="{ data:cellInfo }">
                        <v-row v-if="!cellInfo.data.__created__" no-gutters>
                          <v-col class="pl-2 pt-1 d-flex" cols="8">
                            <span v-if="cellInfo.column.dataField == 'logo'" class="dx-datagrid-content-file-name-text">
                              {{ cellInfo.data.logoFileNm ? cellInfo.data.logoFileNm + '.' : ' (파일없음)'
                              }}{{ cellInfo.data.logo ? cellInfo.data.logo : '' }}
                            </span>
                            <span v-else-if="cellInfo.column.dataField == 'seal'" class="dx-datagrid-content-file-name-text">
                              {{ cellInfo.data.sealFileNm ? cellInfo.data.sealFileNm + '.' : ' (파일없음)'
                              }}{{ cellInfo.data.seal ? cellInfo.data.seal : '' }}
                            </span>
                            <span class="pl-2 d-flex align-center">
                              <div v-if="cellInfo.value == '' || cellInfo.value == null" />

                              <svg-icon class="jpg_icon mr-2" v-else-if="cellInfo.value == 'jpg' || cellInfo.value == 'jpeg'" icon-class="jpg" />

                              <svg-icon class="png_icon mr-2" v-else-if="cellInfo.value == 'png'" icon-class="png" />

                              <svg-icon class="file_default_icon ml-2" v-else icon-class="file_default" />

                              <v-btn
                                v-if="cellInfo.value"
                                elevation="0"
                                color="btn_sub"
                                dark
                                x-small
                                @click="fileDownload(cellInfo.column.dataField, cellInfo.data)"
                              >
                                <!-- <svg-icon icon-class="download"></svg-icon> -->
                                다운로드
                              </v-btn>
                            </span>
                          </v-col>
                          <v-col align="right" cols="4">
                            <v-btn icon v-if="cellInfo.value" role="clear" @click="clearClick(cellInfo)">
                              <svg-icon icon-class="close"></svg-icon>
                            </v-btn>
                            <v-btn elevation="0" color="btn_sub" dark x-small class="pa-1 mr-2" role="upload" @click="uploadClick(cellInfo)">
                              <!-- <svg-icon icon-class="upload"></svg-icon> -->
                              업로드
                              <!-- 업로드 -->
                            </v-btn>
                          </v-col>
                        </v-row>
                      </template>
                    </DxDataGrid>

                    <DxFileUploader
                      :ref="dxSealFileloaderRef"
                      :multiple="false"
                      upload-mode="useButton"
                      :visible="false"
                      @value-changed="onFileValueChanged"
                      :accept="accept"
                    />

                    <DxFileUploader
                      :ref="dxLogoFileloaderRef"
                      :multiple="false"
                      upload-mode="useButton"
                      :visible="false"
                      @value-changed="onFileValueChanged"
                      :accept="accept"
                    />
                  </v-col>
                </v-col>
              </v-layout>
            </template>
          </i-card-vertical>
        </v-col>
      </v-layout>
    </v-row>
  </v-container>
</template>

<script>
import { DxLookup, DxPatternRule } from 'devextreme-vue/data-grid'
import DxDropDownBox from 'devextreme-vue/drop-down-box'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'

import { DxFileUploader } from 'devextreme-vue/file-uploader'
import { multiUpload, downloadFile } from '@/api/baseManage/fileUpload'
import notify from 'devextreme/ui/notify'

import { getExtension } from '@/utils/common.js'
import { getCompanyData, getCompanyList, saveCompany, deleteCompany } from '@/api/setting/compManage'
import { getClientId } from '@/api/setting/clientManage'
import { validCompanyRegNumber, validCorpRegNumber, validCompId, validEmail, validTell } from '@/utils/validate.js'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
  name: 'compManage',
  components: {
    'i-card-vertical': iCardVertical,
    'i-card-top': iCardTop,
    DxLookup,
    DxDropDownBox,
    DxPatternRule,
    DxFileUploader
  },
  data() {
    return {
      accept: 'image/*',
      dxSealFileloaderRef: 'sealFileUploaderRef',
      dxLogoFileloaderRef: 'logoFileUploaderRef',
      dxDataGridRef: 'companyDataGrid',
      companys: [],
      valid: true,
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      focusData: [],
      clientList: [],
      selectedClient: [],
      selectClient: null,
      allMode: 'allPages',
      dropDownOptions: { width: 350 },
      postCdDropBoxRefName: 'postCdDropBoxRef',
      allowedFileExtensions: ['jpg', 'jpeg', 'gif', 'png'],
      currentValue: '',
      postVisible: false,
      // phonePattern: /^\d{3}-(\d{4}||\d{3})-\d{4}$/i,
      rgstNoPattern: /^\d{3}-\d{2}-\d{5}$/i,
      corpNoPattern: /^\d{6}-\d{7}$/i,
      compIdPattern: /^[A-Za-z0-9]{1,5}$/i
    }
  },
  computed: {},
  beforeMount() {
    getClientId()
      .then(res => {
        if (res.success) {
          this.clientList = []
          this.clientList = res.list
        }
      })
      .catch(error => {})
  },
  mounted() {
    // 켜질때 조회
    this.btnSearch(true)
  },
  methods: {
    //dropDown이 열릴때 타는 이벤트
    onOpened(e) {
      this.postVisible = true
    },
    //dropDown이 닫힐때 타는 이벤트
    onClosed(e) {
      this.postVisible = false
    },
    //우편번호를 화면에 표시해주는 함수
    setPostCd() {
      return this.$refs.postCdDropBoxRef.value
    },
    getSearch(e) {},
    //우편번호 선택 완료시 타는 이벤트
    getAddress(e, cellInfo) {
      this.currentValue = e.zonecode

      //선택된 우편번호에 대한 정보를 설정
      this.GetDataGrid(this.dxDataGridRef).cellValue(cellInfo.rowIndex, 'zipCd', e.zonecode)
      this.GetDataGrid(this.dxDataGridRef).cellValue(cellInfo.rowIndex, 'addrs1', e.address)
      this.GetDataGrid(this.dxDataGridRef).cellValue(cellInfo.rowIndex, 'addrsEn1', e.addressEnglish)

      cellInfo.component.updateDimensions()
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.key, true)
      this.GetDataGrid(this.dxDataGridRef).saveEditData()
    },
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    //------------------------------------------
    //  사업장 조회
    //------------------------------------------
    btnSearch(isNotify) {
      this.openLoading('searching')
      this.companys = []
      getCompanyList(isNotify)
        .then(res => {
          if (res.success) {
            this.gridInit(this.GetDataGrid(this.dxDataGridRef))
            this.companys = res.list
            this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
          }
        })
        .catch(error => {})
        .finally(() => {
          this.endLoading()
        })
    },
    //------------------------------------------
    //  사업장 추가
    //------------------------------------------
    btnAdd() {
      const createdArr = this.companys.filter(el => el.__created__)
      const newId = (Math.max(...createdArr.map(obj => obj.id)) || 0) + 1
      let newRow = {
        id: createdArr.length !== 0 ? newId : 1,
        clntId: null,
        clntNm: null,
        zipCd: null,
        addrs1: '',
        addrs2: '',
        addrsEn1: '',
        addrsEn2: '',
        natnCd: 'KR',
        rgstNo: '',
        corpNo: '',
        faxNo: '',
        telNo: ''
      }

      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })

      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    //------------------------------------------
    //  사업장 저장
    //------------------------------------------
    async btnSave() {
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowsData()
        .then(selectedRows => {
          if (selectedRows.length === 0) {
            this.vToastify(this.$t('selectionData'), 'warn')
            return
          }
          //저장하기전에 필수입력값이 다 입력되었는지 확인

          // var emailPattern = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/g

          // if (!emailPattern.test(params[0].email) && (params[0].email.length != 0 || params[0].email != '')) {
          //   this.$vToastify.warning({ body: this.$t('이메일 형식에 맞지않습니다.') })
          //   return
          // }
          this.vToastifyPrompt(
            this.$t('doSaveData'),
            'info',
            current => {
              this.GetDataGrid(this.dxDataGridRef).beginUpdate()
              this.GetDataGrid(this.dxDataGridRef).saveEditData()

              //필수입력값 체크
              var pattern = /\s/g
              var index = selectedRows.findIndex(
                element =>
                  element.clntId == null ||
                  element.compId == null ||
                  element.compNm == null ||
                  element.rgstNo == null ||
                  element.rpstNm == null ||
                  element.clntId == '' ||
                  element.compId == '' ||
                  element.compNm == '' ||
                  element.rgstNo == '' ||
                  element.rpstNm == '' ||
                  element.compId.match(pattern) != null
              )

              if (index >= 0) {
                this.vToastify(`${this.$t('msgReqValidate')}`, 'warn')
                this.GetDataGrid(this.dxDataGridRef).endUpdate()
                return
              }

              //유효성 검사
              var valid = ''
              var patternIndex = selectedRows.findIndex(element => {
                console.log(element)
                if (!validCompId(element.compId)) {
                  valid = 'compId'
                  return true
                } else if (!validCompanyRegNumber(element.rgstNo)) {
                  valid = 'rgstNo'
                  return true
                } else if (!validCorpRegNumber(element.corpNo) && element.corpNo != null && element.corpNo != '') {
                  valid = 'corpNo'
                  return true
                } else if (!validEmail(element.email) && element.email != null && element.email != '') {
                  valid = 'email'
                  return true
                } else if (element.email != null && element.email != '' && element.email.length > 50) {
                  valid = 'email2'
                  return true
                } else if (!validTell(element.telNo) && element.telNo != null && element.telNo != '') {
                  valid = 'telNo'
                  return true
                } else if (!validTell(element.faxNo) && element.faxNo != null && element.faxNo != '') {
                  valid = 'faxNo'
                  return true
                }
              })

              if (patternIndex >= 0) {
                this.vToastify(
                  valid == 'compId'
                    ? this.$t('사업장 번호는 영문,숫자 10자 이내로 입력해주세요.')
                    : valid == 'rgstNo'
                    ? this.$t('올바르지 않은 사업자등록번호 형식입니다.')
                    : valid == 'email'
                    ? this.$t('올바르지 않은 이메일 형식입니다.')
                    : valid == 'email2'
                    ? this.$t('이메일은 50자 이내로 입력하세요.')
                    : valid == 'corpNo'
                    ? this.$t('올바르지 않은 법인등록번호 형식입니다.')
                    : valid == 'telNo'
                    ? this.$t('올바르지 않은 전화번호 형식입니다.')
                    : valid == 'faxNo'
                    ? this.$t('올바르지 않은 팩스번호 형식입니다.')
                    : this.$t(''),
                  'warn'
                )
                this.GetDataGrid(this.dxDataGridRef).endUpdate()
                return
              }
              let fileData = []
              //사업장명, 대표자명 앞뒤 공백 제거
              selectedRows.forEach(element => {
                element.compNm = element.compNm.trim()
                element.rpstNm = element.rpstNm.trim()
                if (
                  (element.sealFile != null && element.sealFile != '' && element.seal__fileUpdate__) ||
                  (element.logoFile != null && element.logoFile != '' && element.logo__fileUpdate__)
                ) {
                  fileData.push(element)
                }
              })

              //저장 api
              this.openLoading('saving')
              saveCompany(selectedRows, true)
                .then(res => {
                  if (res.success) {
                    if (fileData.length !== 0) {
                      this.saveFile(fileData).then(res => {
                        this.btnSearch(false)
                      })
                    } else {
                      this.btnSearch(false)
                    }
                  }
                })
                .catch(error => {
                  if (error.response && error.response.data) {
                    if (error.response.data.code == -2001) {
                      this.vToastify(this.$t(error.response.data.msg), 'warn')
                    }
                  }
                })
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.endLoading()
                })
            },
            null,
            true
          )
        })
    },
    //------------------------------------------
    //  사업장 삭제
    //------------------------------------------
    btnDelete() {
      let createdRows = []
      let selectedRows = []
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowsData()
        .then(allSelectedRows => {
          if (allSelectedRows.length === 0) {
            this.vToastify(this.$t('selectionData'), 'warn')
            return
          }
          allSelectedRows.forEach(item => {
            if (item.__created__ == true) createdRows.push(item)
            else selectedRows.push(item)
          })
          if (selectedRows.length === 0) {
            this.deleteCallBack(createdRows)
            return
          }
          this.vToastifyPrompt(
            this.$t('doDeleteData'),
            'info',
            current => {
              this.GetDataGrid(this.dxDataGridRef).beginUpdate()
              this.GetDataGrid(this.dxDataGridRef).saveEditData()

              this.openLoading('deleting')
              //삭제 api
              deleteCompany(selectedRows, true)
                .then(res => {
                  if (res.success) {
                    this.deleteCallBack(allSelectedRows)
                    this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  }
                })
                .catch(error => {})
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  this.endLoading()
                })
            },
            null,
            true
          )
        })
    },

    ///////////////////////////////////////
    /*           DataGrid Event          */
    ///////////////////////////////////////
    onEditingStart(e) {
      if ((e.column.dataField == 'clntId' || e.column.dataField == 'compId') && !e.data.__created__) e.cancel = true
      else if (e.column.dataField == 'clntNm') e.cancel = true
      else if (e.column.dataField == 'addrs1' || e.column.dataField == 'addrsEn1') e.cancel = true
      else e.cancel = false
    },
    onCellValueChanged(value, cellInfo) {
      //수정한 행이 clntId의 경우 선택한 clntId의 값에 따라 clntNm필드값 변경
      if (cellInfo.dataField == 'clntId') {
        let index = this.clientList.findIndex(element => element.clntId == value)
        if (index > -1) {
          this.GetDataGrid(this.dxDataGridRef).cellValue(cellInfo.index, 'clntNm', this.clientList[index].clntNm)
          this.GetDataGrid(this.dxDataGridRef).cellValue(cellInfo.index, 'clntId', value)
        }
      }

      cellInfo.setValue(value)
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.row.key, true)
    },
    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(param) {
      var index = null
      param.forEach(key => {
        index = this.companys.findIndex(obj => obj == key)
        this.companys.splice(index, 1)
      })
    },
    //우편번호 삭제 버튼 클릭 시 타는 이벤트
    resetZipCd(e) {
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.rowIndex, 'zipCd', '')
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.rowIndex, 'addrs1', null)
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.rowIndex, 'addrsEn1', null)
    },
    ///////////////////////////////////////
    /*          fileUpload Event         */
    ///////////////////////////////////////
    async onFileValueChanged(e) {
      let file = e.value[0]
      // let index = this.allowedFileExtensions.findIndex(element => element == )
      // file 객체를 data에 넣으면 Error로 인하여 file을 string으로 변환 후 넣음
      var reader = new FileReader()
      reader.readAsDataURL(file)
      reader.onload = () => {
        // 확장자랑 파일명 가져오기
        let subFileName = getExtension(file.name)

        let index = this.allowedFileExtensions.findIndex(element => element == subFileName[1])

        if (index < 0) {
          notify(this.$t('업로드할 수 없는 확장자입니다.'), 'error', 300)
          return
        }
        // console.log(subFileName)
        let rowIndex = this.currentCellInfo.row.rowIndex

        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, this.currentCellInfo.column.dataField, subFileName[1])
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, this.currentCellInfo.column.dataField + 'FileNm', subFileName[0])
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, this.currentCellInfo.column.dataField + 'File', reader.result)
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, this.currentCellInfo.column.dataField + '__fileUpdate__', true)

        let a = this.GetDataGrid(this.dxDataGridRef).option('editing.changes')

        // 수정된 값 표시를 위해 클래스 추가
        // 포커싱이 아웃되면 클래스가 사라짐 개선 필요
        // let cellElement = this.GetDataGrid(this.dxDataGridDetailRef).getCellElement(rowIndex, this.currentCellInfo.columnIndex)
        // let className = ['dx-item-modified', 'dx-cell-modified']
        // cellElement.classList.add(...className)

        this.GetDataGrid(this.dxDataGridRef).selectRows(this.currentCellInfo.key, true)
      }
      reader.onerror = error => {
        // console.log('error', error)
        // this.$vToastify.error({ body: '파일업로드에 실패하였습니다. 다시 시도해주시기 바랍니다.' })
        this.vToastify(this.$t('파일업로드에 실패하였습니다. 다시 시도해주시기 바랍니다.'), 'error')
      }
    },
    uploadClick(e) {
      // 클릭했을 때 해당 열의 데이터를 들고 옴
      this.currentCellInfo = e
      let fileInstance = this.$refs[this.dxLogoFileloaderRef].instance
      let fileElement = fileInstance.element()
      let uploadButton = fileElement.querySelector(`.dx-button-content`)
      uploadButton.click()
    },
    clearClick(e) {
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.row.rowIndex, e.column.dataField, '')
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.row.rowIndex, e.column.dataField + 'FileNm', '')
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.row.rowIndex, e.column.dataField + 'File', '')
      this.GetDataGrid(this.dxDataGridRef).cellValue(e.row.rowIndex, e.column.dataField + '__fileUpdate__', true)

      this.GetDataGrid(this.dxDataGridRef).selectRows(e.key, true)
    },

    saveFile(selectedDetailRows) {
      return new Promise((resolve, reject) => {
        selectedDetailRows.forEach(element => {
          // string변환된 파일을 다시 File 객체로
          if (element.sealFile != null && element.sealFile != '') {
            let arr = element.sealFile.split(','),
              mime = arr[0].match(/:(.*?);/)[1],
              bstr = atob(arr[1]),
              n = bstr.length,
              u8arr = new Uint8Array(n)

            while (n--) {
              u8arr[n] = bstr.charCodeAt(n)
            }
            let file = new File([u8arr], `${element.sealFileNm}.${element.seal}`, { type: mime })

            // form 데이터로 전송
            let formData = new FormData()

            formData.append('files[]', file)

            let fileVO = {
              fileId: null,
              targetId: 'seal_' + element.clntId + '_' + element.compId,
              targetType: 'seal',
              useYn: 'Y',
              compId: 'IGNS'
            }
            formData.append('FileVO', new Blob([JSON.stringify(fileVO)], { type: 'application/json' }))
            multiUpload(formData, false)
              .then(res => {
                notify(this.$t('save.success'), 'success', 300)
              })
              .finally(() => {
                resolve(true)
              })
          }
          if (element.logoFile != null && element.logoFile != '') {
            let arr = element.logoFile.split(','),
              mime = arr[0].match(/:(.*?);/)[1],
              bstr = atob(arr[1]),
              n = bstr.length,
              u8arr = new Uint8Array(n)

            while (n--) {
              u8arr[n] = bstr.charCodeAt(n)
            }
            let file = new File([u8arr], `${element.logoFileNm}.${element.logo}`, { type: mime })

            // form 데이터로 전송
            var formData = new FormData()

            formData.append('files[]', file)

            let fileVO = {
              fileId: null,
              targetId: 'logo_' + element.clntId + '_' + element.compId,
              targetType: 'logo',
              useYn: 'Y',
              compId: 'IGNS'
            }

            formData.append('FileVO', new Blob([JSON.stringify(fileVO)], { type: 'application/json' }))
            multiUpload(formData, false)
              .then(res => {
                notify(this.$t('save.success'), 'success', 300)
              })
              .finally(() => {
                resolve(true)
              })
          }
        })
      })
    },
    fileDownload(dataField, e) {
      if (dataField == 'logo') {
        // 올리지 않은 상태로 파일을 다운 받는 경우
        if (e.logoFile != null && e.logoFile !== '') {
          let link = document.createElement('a')
          link.href = e.logoFile
          link.download = `${e.logoFileNm}.${e.logo}`
          link.click()
        } else if (e.logoFileId != null && e.logoFileId !== '') {
          this.openLoading()
          downloadFile(e.logoFileId)
            .then(res => {
              let link = document.createElement('a')
              // 객체를 만들어서 생성
              let objectUrl = window.URL.createObjectURL(res)
              link.href = objectUrl
              link.download = `${e.logoFileNm}.${e.logo}`
              link.click()
            })
            .finally(() => this.endLoading())
        } else {
          console.error('error', e)
        }
      } else {
        // 올리지 않은 상태로 파일을 다운 받는 경우
        if (e.sealFile != null && e.sealFile !== '') {
          let link = document.createElement('a')
          link.href = e.sealFile
          link.download = `${e.sealFileNm}.${e.seal}`
          link.click()
        } else if (e.sealFileId != null && e.sealFileId !== '') {
          this.openLoading()
          downloadFile(e.sealFileId)
            .then(res => {
              let link = document.createElement('a')
              // 객체를 만들어서 생성
              let objectUrl = window.URL.createObjectURL(res)
              link.href = objectUrl
              link.download = `${e.sealFileNm}.${e.seal}`
              link.click()
            })
            .finally(() => this.endLoading())
        } else {
          console.error('error', e)
        }
      }
    }
  }
}
</script>

